import React, { useState } from "react";
import ListaPeriodos from "./ListaPeriodos";
import FormPeriodos from "./FormPeriodos";
import Modal from "./Modal"; // Ajuste o caminho se necessário

export default function TelaPeriodos() {
  const [mostrarModal, setMostrarModal] = useState(false);
  const [editando, setEditando] = useState(null);
  const [reloadKey, setReloadKey] = useState(0);

  const handleNovo = () => {
    setEditando(null);
    setMostrarModal(true);
  };

  const handleSalvar = () => {
    setMostrarModal(false);
    setEditando(null);
    setReloadKey((v) => v + 1); // Força atualização da lista
  };

  const handleEditar = (periodo) => {
    setEditando(periodo);
    setMostrarModal(true);
  };

  const handleCancel = () => {
    setMostrarModal(false);
    setEditando(null);
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-2xl font-bold">Períodos</h2>
        <button
          onClick={handleNovo}
          className="bg-blue-600 text-white px-4 py-2 rounded"
        >
          Novo Período
        </button>
      </div>
      <ListaPeriodos onEditar={handleEditar} reloadKey={reloadKey} />
      <Modal isOpen={mostrarModal} onRequestClose={handleCancel}>
        <FormPeriodos
          periodoEditando={editando}
          onSalvar={handleSalvar}
          onCancel={handleCancel}
        />
      </Modal>
    </div>
  );
}
